function distinctSubseqII(s) {
    const mod = 1e9 + 7;
    const n = s.length;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    const last = new Array(26).fill(-1);

    for (let i = 1; i <= n; ++i) {
        dp[i] = (dp[i - 1] * 2) % mod;
        if (last[s.charCodeAt(i - 1) - 'a'.charCodeAt()] !== -1) {
            dp[i] = (dp[i] - dp[last[s.charCodeAt(i - 1) - 'a'.charCodeAt()]] + mod) % mod;
        }
        last[s.charCodeAt(i - 1) - 'a'.charCodeAt()] = i - 1;
    }

    dp[n] = (dp[n] - 1 + mod) % mod;
    return dp[n];
}
```


    1. Initialize a dynamic programming array `dp` with length `n+1` to store the number of distinct subsequences.
2. Initialize an array `last`, with length 26, to store the last occurrences of each letter 'a'-'z'.
3. Iterate through the string using the index `i` ranging from `1` to `n`.
   1. Calculate the number of distinct subsequences of length i by doubling the number of distinct subsequences of length i-1.
   2. If the last occurrence of the current letter is not `-1`, subtract the number of distinct subsequences at the index of the last occurrence from the current dp[i] value.
   3. Update the last occurrence array index of the current letter in the string.
4. Subtract 1 from the number of subsequences of length `n` (removes the empty subsequence) and return the result modulo 1e9+7.

